package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_androidType() throws Exception {
    Class<?> androidClass = createClassWithName("android.mock.Class");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClass));
  }

  @Test
  void testIsAnyPlatformType_kotlinPackage() throws Exception {
    Class<?> kotlinClass = createClassWithName("kotlin.SomeClass");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_kotlinxPackage() throws Exception {
    Class<?> kotlinxClass = createClassWithName("kotlinx.SomeClass");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_scalaPackage() throws Exception {
    Class<?> scalaClass = createClassWithName("scala.SomeClass");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_otherPackage() throws Exception {
    Class<?> otherClass = createClassWithName("com.example.SomeClass");
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(otherClass));
  }

  // Use a dynamic subclass with overridden getName to simulate Class<?> with custom name
  private static Class<?> createClassWithName(String name) throws Exception {
    return new ClassWithName(name).getClass();
  }

  private static class ClassWithName extends Class<?> {
    private final String name;

    ClassWithName(String name) {
      super();
      this.name = name;
    }

    @Override
    public String getName() {
      return name;
    }
  }
}
